async function translateWords(words, lang) {
  const useKinship = KINSHIP_LANGUAGES.includes(lang);
  const result = [];

  for (const w of words) {
    const key = w.word?.toLowerCase();

    // Check if this word has kinship variants for this language
    if (useKinship && KINSHIP_VARIANTS[key]?.[lang]) {
      const variants = KINSHIP_VARIANTS[key][lang];
      for (const v of variants) {
        result.push({
          ...w,
          word: v.word,
          emoji: v.emoji || w.emoji,
          note: v.note,                // "older sister", "paternal grandma", etc.
          original: w.word,
        });
      }
      continue;
    }

    // Regular translation path
    const hit = CORE_TRANSLATIONS[key]?.[lang] || EXTRA_TRANSLATIONS[key]?.[lang];
    if (hit) {
      result.push({ ...w, word: hit, original: w.word });
    } else {
      result.push({ ...w, original: w.word });
    }
  }

  return result;
}

async function fetchDailyWords(dk) {
  // Deterministic day number for curriculum rolling window
  const dayNum = getDayNumber();
  const rolling = getRollingSets(WORD_SETS, dayNum);
  return buildDeckFromSets(rolling);
}

