function translateKnowledgeCard(card, lang) {
  if (lang === "English") return { ...card, original: null };
  // Look up by id, or fall back to title (for cached cards from earlier versions)
  const key = card.id || card.title;
  // Check both the original 12-card table and the new themed-sets table
  const tr = KNOWLEDGE_SET_TRANSLATIONS[key]?.[lang] || KNOWLEDGE_TRANSLATIONS[key]?.[lang];
  if (!tr) return { ...card, original: null };
  return {
    ...card,
    title: tr.title,
    fact: tr.fact,
    original: { title: card.title, fact: card.fact },
  };
}

async function fetchDailyKnowledge(dk) {
  const dayNum = getDayNumber();
  const rolling = getRollingSets(KNOWLEDGE_SETS, dayNum);
  return buildDeckFromSets(rolling);
}

