function ProgressScreen({ child, onBack }) {
  const hist = useMemo(()=>getHistory(child?.id), [child?.id]);
  const dayNum = useMemo(()=>getDayNumber(), []);
  const dates = Object.keys(hist).sort().reverse();

  // Aggregate totals by category & by language
  const byCategory = { reading: 0, math: 0, encyclopedia: 0, couplets: 0, sentences: 0, book: 0 };
  const byLanguage = {};
  dates.forEach(d => {
    const day = hist[d] || {};
    Object.entries(day).forEach(([k, count]) => {
      const [cat, lang] = k.split(":");
      if (byCategory[cat] !== undefined) byCategory[cat] += count;
      if (lang) byLanguage[lang] = (byLanguage[lang] || 0) + count;
    });
  });
  const grandTotal = byCategory.reading + byCategory.math + byCategory.encyclopedia + byCategory.couplets + byCategory.sentences + byCategory.book;

  const streak = useMemo(()=>computeStreak(hist), [hist]);
  const today = todayKey();
  const oneDay = 1000 * 60 * 60 * 24;

  // Today's progress per category (summing all languages)
  const todayData = { reading: 0, math: 0, encyclopedia: 0, couplets: 0, sentences: 0, book: 0 };
  const todayHist = hist[today] || {};
  Object.entries(todayHist).forEach(([k, count]) => {
    const [cat] = k.split(":");
    if (todayData[cat] !== undefined) todayData[cat] += count;
  });

  const StatCard = ({ label, value, emoji, big }) => (
    <div style={{flex:1,background:"#fff",border:"2px solid #f0f0f0",borderRadius:18,padding:"16px 14px",textAlign:"center",minWidth:0}}>
      <div style={{fontSize:big?30:22,marginBottom:4}}>{emoji}</div>
      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:big?32:22,color:RED,lineHeight:1}}>{value}</div>
      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#aaa",marginTop:4,textTransform:"uppercase",letterSpacing:.5}}>{label}</div>
    </div>
  );

  const dayLabel = (d) => {
    const dt = new Date(d + "T00:00:00");
    if (d === today) return "today";
    const diff = Math.round((new Date(today+"T00:00:00") - dt) / oneDay);
    if (diff === 1) return "yesterday";
    if (diff < 7) return dt.toLocaleDateString(undefined, { weekday:"long" }).toLowerCase();
    return dt.toLocaleDateString(undefined, { month:"short", day:"numeric" }).toLowerCase();
  };

  const TodayRow = ({ label, emoji, done }) => (
    <div style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#fafafa",borderRadius:14}}>
      <span style={{fontSize:22}}>{emoji}</span>
      <span style={{flex:1,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#333"}}>{label}</span>
      <div style={{display:"flex",gap:5}}>
        {[1,2,3].map(i => (
          <div key={i} style={{width:10,height:10,borderRadius:"50%",background:i<=done?RED:"#e0e0e0"}}/>
        ))}
      </div>
    </div>
  );

  // Get per-language summary for a day
  const dayByLang = (day) => {
    const langs = {};
    Object.entries(day||{}).forEach(([k, c]) => {
      const [, lang] = k.split(":");
      if (lang) langs[lang] = (langs[lang] || 0) + c;
    });
    return langs;
  };

  // Sort languages by total sessions descending
  const languageEntries = Object.entries(byLanguage).sort((a,b)=>b[1]-a[1]);

  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 18px",borderBottom:"1px solid #f5f5f5"}}>
        <button onClick={onBack} style={{background:"#f5f5f5",border:"none",borderRadius:50,width:38,height:38,fontSize:17,cursor:"pointer",color:"#555",display:"flex",alignItems:"center",justifyContent:"center"}}>←</button>
        <div style={{textAlign:"center"}}>
          <h2 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:18,color:"#111",margin:0}}>Progress</h2>
          {child && <p style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#aaa",margin:"2px 0 0"}}>{child.emoji} {child.name}</p>}
        </div>
        <div style={{width:38}}/>
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"18px 18px 32px"}}>
        {grandTotal === 0 ? (
          <div style={{textAlign:"center",padding:"60px 24px"}}>
            <div style={{fontSize:56,marginBottom:12}}>🌱</div>
            <p style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:22,color:"#111",marginBottom:8}}>No sessions yet</p>
            <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:14,color:"#aaa",maxWidth:280,margin:"0 auto",lineHeight:1.4}}>
              Tap Reading, Math, or Knowledge to get started!
            </p>
          </div>
        ) : (
          <>
            <div style={{display:"flex",gap:10,marginBottom:18}}>
              <StatCard label="day" value={dayNum} emoji="🗓️" big/>
              <StatCard label="streak" value={streak} emoji="🔥" big/>
              <StatCard label="sessions" value={grandTotal} emoji="⭐" big/>
            </div>

            {/* CEFR-adjacent vocabulary milestone */}
            {(() => {
              const vocab = countUniqueWordsExposed(hist);
              const milestone = cefrForVocabCount(vocab);
              return (
                <div style={{marginBottom:22,background:"linear-gradient(135deg,#FFF0F1 0%,#FFE4E6 100%)",border:`2px solid ${RED}`,borderRadius:18,padding:"16px 18px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:6}}>
                    <span style={{fontSize:28}}>🎓</span>
                    <div style={{flex:1}}>
                      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:18,color:RED,lineHeight:1.1}}>{milestone.level}</div>
                      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#888",marginTop:2}}>{milestone.description}</div>
                    </div>
                    <div style={{textAlign:"right"}}>
                      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:20,color:RED,lineHeight:1}}>~{vocab}</div>
                      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:10,color:"#aaa",textTransform:"uppercase",letterSpacing:.5}}>words</div>
                    </div>
                  </div>
                  <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#999",lineHeight:1.4,marginTop:8,fontStyle:"italic"}}>
                    Vocabulary exposure mapped to CEFR vocabulary-size thresholds. Not a formal assessment.
                  </div>
                </div>
              );
            })()}

            <div style={{marginBottom:22}}>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>today</h3>
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {(() => {
                  const dayNum = getDayNumber();
                  return (
                    <>
                      <TodayRow label="Reading" emoji="📖" done={todayData.reading}/>
                      {dayNum >= 31 && <TodayRow label="Couplets" emoji="📝" done={todayData.couplets||0}/>}
                      {dayNum >= 61 && <TodayRow label="Sentences" emoji="✍️" done={todayData.sentences||0}/>}
                      {dayNum >= 91 && <TodayRow label="Book" emoji="📚" done={todayData.book||0}/>}
                      <TodayRow label="Math" emoji="🔢" done={todayData.math}/>
                      <TodayRow label="Knowledge" emoji="🌍" done={todayData.encyclopedia}/>
                    </>
                  );
                })()}
              </div>
            </div>

            <div style={{marginBottom:22}}>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>by category</h3>
              <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
                <StatCard label="reading" value={byCategory.reading} emoji="📖"/>
                <StatCard label="math" value={byCategory.math} emoji="🔢"/>
                <StatCard label="knowledge" value={byCategory.encyclopedia} emoji="🌍"/>
              </div>
            </div>

            {languageEntries.length > 0 && (
              <div style={{marginBottom:22}}>
                <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>by language</h3>
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {languageEntries.map(([lang, count])=>{
                    const maxCount = languageEntries[0][1];
                    const pct = Math.max(8, (count/maxCount)*100);
                    return (
                      <div key={lang} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#fafafa",borderRadius:12}}>
                        <span style={{flex:"0 0 110px",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#333"}}>{lang}</span>
                        <div style={{flex:1,height:8,background:"#efefef",borderRadius:4,overflow:"hidden"}}>
                          <div style={{height:"100%",width:`${pct}%`,background:RED,borderRadius:4,transition:"width .4s"}}/>
                        </div>
                        <span style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:14,color:RED,minWidth:26,textAlign:"right"}}>{count}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>recent days</h3>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {dates.slice(0,14).map(d => {
                  const day = hist[d];
                  let total = 0;
                  Object.values(day).forEach(v => { total += v; });
                  const langs = Object.entries(dayByLang(day)).sort((a,b)=>b[1]-a[1]).slice(0,3);
                  return (
                    <div key={d} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#fafafa",borderRadius:12}}>
                      <span style={{flex:"0 0 88px",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#555",textTransform:"capitalize"}}>{dayLabel(d)}</span>
                      <span style={{flex:1,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#aaa",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                        {langs.map(([l,c]) => `${l} ${c}`).join(" · ") || "—"}
                      </span>
                      <span style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:14,color:total>=9?RED:"#bbb",minWidth:22,textAlign:"right"}}>{total}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

